const base = $('calculate_species_parameters').first().json || {};
const raw = $json || {};
const content = String((((raw || {}).choices || [])[0] || {}).message?.content || '').trim();
if (!content) return [{ json: { ...base, analysisFallbackUsed: true } }];
let parsed;
try { parsed = JSON.parse(content); } catch (_error) { return [{ json: { ...base, analysisFallbackUsed: true } }]; }
const allowed = new Set((Array.isArray(base.topPredictedPoints) ? base.topPredictedPoints : []).map((point) => String(point.name || '') + '|' + Number(point.lat || 0) + '|' + Number(point.lon || 0)));
const reranked = Array.isArray(parsed.rerankedTopPredictedPoints) ? parsed.rerankedTopPredictedPoints : [];
for (const point of reranked) {
  const key = String(point?.name || '') + '|' + Number(point?.lat || 0) + '|' + Number(point?.lon || 0);
  if (!allowed.has(key)) return [{ json: { ...base, analysisFallbackUsed: true } }];
}
return [{ json: { ...base, parsedOpenAIAnalysis: parsed, analysisFallbackUsed: false } }];

const base = $json || {};
const analysis = base.parsedOpenAIAnalysis;
if (!analysis || typeof analysis !== 'object') return [{ json: { ...base, analysisFallbackUsed: true } }];
const openaiAnalysis = {
  analysisVersion: String(analysis.analysisVersion || 'openai_v1'),
  insightSummary: String(analysis.insightSummary || base.insightSummary || ''),
  confidenceNote: String(analysis.confidenceNote || ''),
  warnings: Array.isArray(analysis.warnings) ? analysis.warnings.map((warning) => String(warning || '').trim()).filter(Boolean) : [],
  rerankedTopPredictedPoints: Array.isArray(analysis.rerankedTopPredictedPoints) ? analysis.rerankedTopPredictedPoints : [],
  consistencyChecks: analysis.consistencyChecks || { routeLooksPlausible: false, timingLooksPlausible: false, weatherLooksSupportive: false, foreignPressureMatchesNarrative: false },
};
return [{ json: { ...base, insightSummary: openaiAnalysis.insightSummary || base.insightSummary || '', analysisVersion: openaiAnalysis.analysisVersion, analysisFallbackUsed: false, confidenceNote: openaiAnalysis.confidenceNote, warnings: openaiAnalysis.warnings, rerankedTopPredictedPoints: openaiAnalysis.rerankedTopPredictedPoints, consistencyChecks: openaiAnalysis.consistencyChecks, openaiAnalysis } }];
